/**
 * Weights & Biases (W&B) API firewall config generator.
 *
 * Data source: https://docs.wandb.ai/ref/rest
 *
 * W&B uses Bearer token authentication.
 * API key format: 40-character hex string.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.wandb.ai/ref/rest";
// Format: 40-character alphanumeric string (hex-based in practice)
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Weights & Biases API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:wandb",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const wandbFirewall = {",
    '  name: "wandb",',
    '  description: "Weights & Biases",',
    "  placeholders: {",
    `    WANDB_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.wandb.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.WANDB_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Weights & Biases firewall config...");
  const ts = generateTypeScript();
  writeOutput("wandb", ts, import.meta.dirname);
}
